  create policy "Payouts delete for admins"
  on "public"."deal_payouts"
  as permissive
  for delete
  to authenticated
using (public.is_admin());



  create policy "Payouts insert for admins"
  on "public"."deal_payouts"
  as permissive
  for insert
  to authenticated
with check (public.is_admin());



  create policy "Payouts select for owner or admin"
  on "public"."deal_payouts"
  as permissive
  for select
  to authenticated
using ((public.is_admin() OR (sales_id = ( SELECT sales.id
   FROM public.sales
  WHERE (sales.user_id = auth.uid())))));



  create policy "Payouts update for admins"
  on "public"."deal_payouts"
  as permissive
  for update
  to authenticated
using (public.is_admin())
with check (public.is_admin());


CREATE TRIGGER deal_won_payout_trigger AFTER INSERT OR UPDATE OF stage ON public.deals FOR EACH ROW EXECUTE FUNCTION public.handle_deal_won_payout();


